/* PoObQtyAvgMapper.xml insertPoObQtyAvg */ INSERT INTO TORDER_INFO_OBSTAT_AVG ( OWKEY , CTKEY , ICKEY , QTY , INSERTDATE , INSERTURKEY , UPDATEDATE , UPDATEURKEY ) SELECT T.OWKEY , T.CTKEY , T.ICKEY , T.QTY , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') AS INSERTDATE , 'BATCH' AS INSERTURKEY , TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS') AS UPDATEDATE , 'BATCH' AS UPDATEURKEY FROM (
SELECT OB.OWKEY , OB.CTKEY , OB.ICKEY , CASE WHEN OB.HWSETYN = 'Y' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN OB.OBFROMDAY AND OB.OBTODAY ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '01' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR(CEIL((CURRENT_TIMESTAMP + (-12) * INTERVAL '1 month'), 'MM'), 'yyyyMMdd') AND TO_CHAR((DATE_TRUNC('month', (CURRENT_TIMESTAMP + (-12) * INTERVAL '1 month')) + INTERVAL '1 month - 1 day')::DATE, 'yyyyMMdd') ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '02' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR((CEIL(CURRENT_TIMESTAMP) + (-12) * INTERVAL '1 month') - 6, 'yyyyMMdd') AND TO_CHAR((CEIL(CURRENT_TIMESTAMP) + (-12) * INTERVAL '1 month'), 'yyyyMMdd') ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '03' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '30 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '04' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '6 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '05' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - (COALESCE(OB.APLYDAYS, 0)), 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') ) WHEN OB.HWSETYN = 'N' AND OBQTYCRITCAL = '06' THEN ( SELECT CEIL(SUM(QTY) / COALESCE(OB.APLYDAYS, 1)) QTY FROM TORDER_INFO_ORDER_STAT S WHERE S.OWKEY = OB.OWKEY AND S.CTKEY = OB.CTKEY AND S.ICKEY = OB.ICKEY AND S.CRITDAY BETWEEN TO_CHAR(CURRENT_TIMESTAMP - INTERVAL '13 days', 'yyyyMMdd') AND TO_CHAR(CURRENT_TIMESTAMP, 'yyyyMMdd') ) ELSE 0 END AS QTY FROM TORDER_MST_OBAVGQTY OB UNION ALL SELECT OWKEY , CTKEY , ICKEY , CEIL(SUM(QTY) / 7) AS QTY FROM ( SELECT OS.OWKEY , OS.CTKEY , OS.ICKEY , OS.CRITDAY , SUM(OS.QTY) AS QTY , ROW_NUMBER() OVER (PARTITION BY OS.OWKEY, OS.CTKEY, OS.ICKEY ORDER BY OS.CRITDAY DESC, OS.ICKEY) AS NUM FROM TORDER_INFO_ORDER_STAT OS WHERE OS.QTY > 0 AND NOT EXISTS ( SELECT 1 FROM TORDER_MST_OBAVGQTY E WHERE OS.OWKEY = E.OWKEY AND OS.CTKEY = E.CTKEY AND OS.ICKEY = E.ICKEY ) GROUP BY OS.OWKEY , OS.CTKEY , OS.ICKEY , OS.CRITDAY ORDER BY OS.ICKEY ) WHERE NUM <= 7 GROUP BY OWKEY , CTKEY , ICKEY
) T LEFT JOIN TORDER_INFO_OBSTAT_AVG AV ON T.OWKEY = AV.OWKEY AND T.CTKEY = AV.CTKEY AND T.ICKEY = AV.ICKEY WHERE AV.ICKEY IS NULL
